#!/usr/bin/env python3
import os,sys,json,glob,time,base64,subprocess,urllib.request
def load_env():
    for q in ("/etc/atlas/autopull.env","/etc/atlas/db.env"):
        if os.path.exists(q):
            for ln in open(q):
                ln=ln.strip()
                if ln.startswith("export "): ln=ln[7:]
                if "=" in ln and not ln.startswith("#"):
                    k,v=ln.split("=",1)
                    if k.strip() not in os.environ: os.environ[k.strip()]=v.strip().strip('"').strip("'")
load_env()
out={"kind":"brain-diag","ts":int(time.time())}
out["paths"]=glob.glob("/opt/atlas/**/brain_improve*.py",recursive=True)+glob.glob("/opt/atlas/**/improve*.py",recursive=True)
out["unit_exec"]=subprocess.run(["bash","-lc","systemctl cat brain-improve-hourly.service 2>/dev/null | grep -E 'ExecStart|WorkingDir'"],capture_output=True,text=True).stdout.strip()
out["journal"]=subprocess.run(["bash","-lc","journalctl -u brain-improve-hourly.service --no-pager -n 30 2>/dev/null | tail -30"],capture_output=True,text=True).stdout[-3000:]
tok=os.environ.get("STATUS_TOKEN"); repo=os.environ.get("STATUS_REPO")
if tok and repo:
    url="https://api.github.com/repos/%s/contents/status/hetzner/brain-diag.json"%repo
    body={"message":"brain-diag","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
    try:
        r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Accept":"application/vnd.github+json"})
        body["sha"]=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
    except Exception: pass
    try:
        rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"User-Agent":"atlas","Content-Type":"application/json","Accept":"application/vnd.github+json"})
        urllib.request.urlopen(rq,timeout=25); print("brain-diag published")
    except Exception as e: print("publish_err",str(e)[:100])
else: print("no_token_env")
